4. You MUST NOT modify ANY formal specification. Do not change requires, ensures, invariant, decreases, function bodies, or predicate bodies.
5. Any modification to existing code or specifications will be automatically detected and rejected. We compare the AST of your output against the original — only added assert statements and new lemma/function definitions are permitted.

Return the complete Dafny program with your added assertions inside <DAFNY_CODE> tags.

```dafny
// Count the consecutive ')' characters at the end of the string.
// This is the mathematical definition of the problem's core concept:
// "the number of characters ')' at the end of the string."
ghost function TrailingParens(s: string): nat
  decreases |s|
{
  if |s| == 0 then 0
  else if s[|s| - 1] == ')' then 1 + TrailingParens(s[..|s| - 1])
  else 0
}

// A message is bad if the trailing ')' count strictly exceeds
// the number of remaining (non-trailing) characters.
ghost predicate IsBad(s: string)
{
  TrailingParens(s) > |s| - TrailingParens(s)
}

method InGameChat(s: string) returns (bad: bool)
  ensures bad == IsBad(s)
{
  var i := |s| - 1;

  while i >= 0 && s[i] == ')'
    invariant -1 <= i <= |s| - 1
    invariant TrailingParens(s) == (|s| - 1 - i) + TrailingParens(s[..i + 1])
  {

    i := i - 1;
  }
  assert TrailingParens(s[..i + 1]) == 0;
  var x := |s| - i - 1;
  bad := x > |s| - x;
}

```

